+func embeddingManifestMatches(opts Options, manifest EmbeddingManifest) bool {
+	if strings.TrimSpace(opts.EmbeddingProvider) != "" && manifest.Provider != strings.ToLower(strings.TrimSpace(opts.EmbeddingProvider)) {
